package com.wjx871.population.export;import com.fasterxml.jackson.core.type.TypeReference;import com.fasterxml.jackson.databind.ObjectMapper;import com.wjx871.population.application.*;import com.wjx871.population.approval.*;import com.wjx871.population.audit.OperationLogService;import com.wjx871.population.common.BusinessException;import com.wjx871.population.security.*;import jakarta.servlet.http.HttpServletRequest;import java.io.*;import java.time.*;import java.time.format.DateTimeFormatter;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.core.io.Resource;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @RequiredArgsConstructor public class ExportService {private final ExportMapper mapper;private final ExportPolicy policy;private final ExportProperties props;private final ExportFileService files;private final SensitiveDataMaskingService masking;private final ObjectMapper json;private final ApplicationService applications;private final BusinessApplicationMapper applicationMapper;private final ApprovalRequestMapper approvalMapper;private final ApprovalLogMapper approvalLogs;private final OperationLogService audit;private final Clock clock;
@Transactional public ExportLogView normal(NormalExportRequest q,HttpServletRequest h){policy.validate(q.module(),q.filters(),q.fields(),false);long count=count(q.module(),q.filters());if(count>props.getNormalMaxRows())throw conflict("导出数据量超过普通导出限制，请缩小查询范围或提交敏感导出申请");AuthenticatedUser u=CurrentUserContext.requireUser();DataExportLog log=newLog(null,q.module(),"NORMAL_MASKED",u,filters(q.filters()),String.join(",",q.fields()));mapper.insertLog(log);try{List<Map<String,Object>> rows=maskedRows(q.module(),q.filters(),q.fields(),props.getNormalMaxRows());ExportFileService.Generated f=files.generate(q.module(),q.fields(),rows,log.getStoredFilename());log.setRowCount(rows.size());log.setFileSha256(f.sha256());log.setFileSize(f.size());if(mapper.completeLog(log)==0)throw conflict("导出记录状态已变化");audit.recordTransactional(u.userId(),"DATA_EXPORT_NORMAL",h);return ExportLogView.from(mapper.findLog(log.getExportLogId()).orElseThrow(),true);}catch(Exception e){files.quietDelete(log.getStoredFilename());throw e instanceof BusinessException b?b:new BusinessException(HttpStatus.INTERNAL_SERVER_ERROR,"导出文件生成失败");}}
@Transactional public Long createSensitive(SensitiveExportRequest q,HttpServletRequest h){policy.validate(q.module(),q.filters(),q.fields(),true);if(q.expectedRowLimit()>props.getSensitiveMaxRows())throw bad("预计导出数量超过敏感导出上限");String filter=filters(q.filters());ApplicationView a=applications.createSpecialized(new ApplicationRequest(BusinessType.SENSITIVE_DATA_EXPORT,q.title(),null,null,q.reason(),q.remark(),null),h);DataExportRequest r=new DataExportRequest();r.setApplicationId(a.applicationId());r.setExportModule(q.module());r.setExportScope(CurrentUserContext.requireUser().dataScope().name());r.setFilterSnapshot(filter);r.setRequestedFields(String.join(",",q.fields()));r.setRequestedFormat("XLSX");r.setReason(q.reason());r.setExpectedRowLimit(q.expectedRowLimit());r.setBusinessStatus("DRAFT");mapper.insertRequest(r);audit.recordTransactional(CurrentUserContext.requireUser().userId(),"DATA_EXPORT_SENSITIVE_APPLY",h);return a.applicationId();}
@Transactional(readOnly=true)public ExportApplicationView application(Long id){BusinessApplication a=applications.require(id);applications.assertCanView(a,CurrentUserContext.requireUser());DataExportRequest r=mapper.findRequest(id).orElseThrow(()->notFound("导出专业详情不存在"));return new ExportApplicationView(ApplicationView.from(a),r,a.getStatus()==ApplicationStatus.APPROVED&&"APPROVED".equals(r.getBusinessStatus()),a.getStatus()==ApplicationStatus.APPROVED?null:"申请尚未批准");}
@Transactional public ExportLogView executeSensitive(Long id,int version,HttpServletRequest h){BusinessApplication a=applications.require(id);if(a.getStatus()!=ApplicationStatus.APPROVED)throw conflict("敏感导出申请尚未批准");DataExportRequest r=mapper.lockRequest(id).orElseThrow(()->notFound("导出专业详情不存在"));if(!"APPROVED".equals(r.getBusinessStatus())||r.getVersion()!=version)ApplicationService.conflict();Map<String,Object> filters=parseFilters(r.getFilterSnapshot());List<String> fields=List.of(r.getRequestedFields().split(","));policy.validate(r.getExportModule(),filters,fields,true);long count=count(r.getExportModule(),filters);if(count>r.getExpectedRowLimit()||count>props.getSensitiveMaxRows())throw conflict("实际导出数量超过批准额度");AuthenticatedUser u=CurrentUserContext.requireUser();DataExportLog log=newLog(id,r.getExportModule(),"SENSITIVE_APPROVED",u,r.getFilterSnapshot(),r.getRequestedFields());log.setRequestedBy(a.getApplicantUserId());mapper.insertLog(log);try{List<Map<String,Object>> rows=mapper.selectRows(r.getExportModule(),filters,DataScopeCriteria.current(),r.getExpectedRowLimit());ExportFileService.Generated f=files.generate(r.getExportModule(),fields,rows,log.getStoredFilename());log.setRowCount(rows.size());log.setFileSha256(f.sha256());log.setFileSize(f.size());if(mapper.completeLog(log)==0)ApplicationService.conflict();if(mapper.updateRequestStatus(id,"APPROVED","COMPLETED",log.getExportLogId(),u.userId())==0)ApplicationService.conflict();complete(a,u,h);audit.recordTransactional(u.userId(),"DATA_EXPORT_SENSITIVE_EXECUTE",h);return ExportLogView.from(mapper.findLog(log.getExportLogId()).orElseThrow(),true);}catch(Exception e){files.quietDelete(log.getStoredFilename());throw e instanceof BusinessException b?b:new BusinessException(HttpStatus.INTERNAL_SERVER_ERROR,"敏感导出执行失败");}}
@Transactional(readOnly=true)public Page<ExportLogView> search(String no,String module,String type,String status,Pageable p){DataScopeCriteria s=DataScopeCriteria.current();List<ExportLogView> rows=mapper.searchLogs(no,module,type,status,s,p.getPageSize(),p.getOffset()).stream().map(x->ExportLogView.from(x,canDownload(x))).toList();return new PageImpl<>(rows,p,mapper.countLogs(no,module,type,status,s));}@Transactional(readOnly=true)public ExportLogView detail(Long id){DataExportLog x=authorized(id);return ExportLogView.from(x,canDownload(x));}
@Transactional public Download download(Long id,HttpServletRequest h){DataExportLog x=mapper.lockLog(id).orElseThrow(()->notFound("导出记录不存在"));assertDownload(x);if(!"COMPLETED".equals(x.getStatus()))throw new BusinessException(HttpStatus.GONE,"导出文件已过期或不可用");try{Resource resource=files.load(x.getStoredFilename());if(mapper.recordDownload(id,x.getVersion())==0)ApplicationService.conflict();audit.recordTransactional(CurrentUserContext.requireUser().userId(),"DATA_EXPORT_DOWNLOAD",h);return new Download(resource,x.getFileName(),"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");}catch(FileNotFoundException e){throw new BusinessException(HttpStatus.GONE,"导出文件已过期或不存在");}catch(IOException e){throw new BusinessException(HttpStatus.INTERNAL_SERVER_ERROR,"导出文件读取失败");}}
private DataExportLog newLog(Long app,String module,String type,AuthenticatedUser u,String filters,String fields){DataExportLog x=new DataExportLog();x.setApplicationId(app);x.setExportNo("EXP-"+LocalDate.now(clock).format(DateTimeFormatter.BASIC_ISO_DATE)+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase());x.setExportModule(module);x.setExportType(type);x.setRequestedBy(u.userId());x.setExecutedBy(u.userId());x.setDepartmentId(u.departmentId());x.setRegionCode(u.regionCode());x.setFilterSnapshot(filters);x.setExportedFields(fields);x.setFileName(module.toLowerCase(Locale.ROOT)+"-"+x.getExportNo()+".xlsx");x.setStoredFilename(UUID.randomUUID()+".xlsx");x.setStoragePath("INTERNAL");return x;}private long count(String module,Map<String,Object> f){return mapper.countRows(module,f==null?Map.of():f,DataScopeCriteria.current());}private List<Map<String,Object>> maskedRows(String module,Map<String,Object> f,List<String> fields,int limit){List<Map<String,Object>> raw=mapper.selectRows(module,f==null?Map.of():f,DataScopeCriteria.current(),limit);List<Map<String,Object>> out=new ArrayList<>();for(Map<String,Object> row:raw){Map<String,Object> m=new LinkedHashMap<>();for(String field:fields){Object v=value(row,field);m.put(field,switch(field){case"maskedIdentityNo"->masking.identityAlways(str(v));case"maskedPhone"->masking.phoneAlways(str(v));case"maskedPermitNo"->masking.permitAlways(str(v));default->v;});}out.add(m);}return out;}private Object value(Map<String,Object> m,String key){String k=switch(key){case"maskedIdentityNo"->"identityNo";case"maskedPhone"->"phone";case"maskedPermitNo"->"permitNo";default->key;};return m.entrySet().stream().filter(e->e.getKey().equalsIgnoreCase(k)).map(Map.Entry::getValue).findFirst().orElse(null);}private String str(Object x){return x==null?null:String.valueOf(x);}private String filters(Map<String,Object> f){try{return json.writeValueAsString(f==null?Map.of():new TreeMap<>(f));}catch(Exception e){throw bad("查询条件无法序列化");}}private Map<String,Object> parseFilters(String s){try{return json.readValue(s,new TypeReference<>(){});}catch(Exception e){throw bad("查询条件快照无效");}}
private DataExportLog authorized(Long id){DataExportLog x=mapper.findLog(id).orElseThrow(()->notFound("导出记录不存在"));AuthenticatedUser u=CurrentUserContext.requireUser();boolean ok=u.dataScope()==DataScope.ALL||x.getRequestedBy().equals(u.userId())||(u.dataScope()==DataScope.DEPARTMENT&&Objects.equals(x.getDepartmentId(),u.departmentId()))||(u.dataScope()==DataScope.REGION&&sameRegion(x.getRegionCode(),u.regionCode()));if(!ok)throw new BusinessException(HttpStatus.FORBIDDEN,"无权访问该导出记录");return x;}private void assertDownload(DataExportLog x){AuthenticatedUser u=CurrentUserContext.requireUser();boolean own=x.getRequestedBy().equals(u.userId())||x.getExecutedBy().equals(u.userId());boolean admin=u.dataScope()==DataScope.ALL;boolean sensitiveAdmin="SENSITIVE_APPROVED".equals(x.getExportType())&&u.permissions().contains("approval:view")&&(admin||sameRegion(x.getRegionCode(),u.regionCode()));if(!(own||admin||sensitiveAdmin))throw new BusinessException(HttpStatus.FORBIDDEN,"无权下载该导出文件");if("NORMAL_MASKED".equals(x.getExportType())&&!u.permissions().contains("data:export:normal")&&!admin)throw new BusinessException(HttpStatus.FORBIDDEN,"缺少普通导出下载权限");if("SENSITIVE_APPROVED".equals(x.getExportType())&&!u.permissions().contains("data:export:sensitive:download")&&!own&&!admin)throw new BusinessException(HttpStatus.FORBIDDEN,"缺少敏感导出下载权限");}private boolean canDownload(DataExportLog x){try{assertDownload(x);return "COMPLETED".equals(x.getStatus());}catch(BusinessException e){return false;}}private boolean sameRegion(String a,String b){return a!=null&&b!=null&&a.length()>=2&&b.length()>=2&&a.substring(0,2).equals(b.substring(0,2));}
private void complete(BusinessApplication a,AuthenticatedUser u,HttpServletRequest h){if(applicationMapper.updateStatus(a.getApplicationId(),ApplicationStatus.APPROVED,ApplicationStatus.COMPLETED,a.getVersion())==0)ApplicationService.conflict();ApprovalRequest ar=approvalMapper.selectByApplicationId(a.getApplicationId()).orElseThrow(()->conflict("审批请求不存在"));approvalLogs.insert(ApprovalLog.of(ar.getApprovalId(),a.getApplicationId(),ApprovalAction.EXECUTE,"APPROVED","COMPLETED",u.userId(),"敏感导出执行完成",audit.clientIp(h)));}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}private BusinessException notFound(String m){return new BusinessException(HttpStatus.NOT_FOUND,m);}record Download(Resource resource,String filename,String contentType){}
}
